INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:17', 53, 17, 27, 526, 4801, 'مَا زَاغَ الْبَصَرُ وَمَا طَغٰى', 'Penglihatan (Nabi Muhammad) tidak menyimpang dan tidak melampaui (apa yang dilihatnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/053017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:18', 53, 18, 27, 526, 4802, 'لَقَدْ رَاٰى مِنْ اٰيٰتِ رَبِّهِ الْكُبْرٰى', ' Sungguh, dia benar-benar telah melihat sebagian tanda-tanda (kebesaran) Tuhannya yang sangat besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/053018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:19', 53, 19, 27, 526, 4803, 'اَفَرَءَيْتُمُ اللّٰتَ وَالْعُزّٰى', 'Apakah patut kamu (orang-orang musyrik) menganggap (dua berhala) al-Lata dan al-‘Uzza,', '', 'https://everyayah.com/data/Alafasy_128kbps/053019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:20', 53, 20, 27, 526, 4804, 'وَمَنٰوةَ الثَّالِثَةَ الْاُخْرٰى ', ' serta Manata (berhala) ketiga yang lain (sebagai anak-anak perempuan Allah yang kamu sembah)?', '', 'https://everyayah.com/data/Alafasy_128kbps/053020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:21', 53, 21, 27, 526, 4805, 'اَلَكُمُ الذَّكَرُ وَلَهُ الْاُنْثٰى ', 'Apakah (pantas) bagi kamu (anak) laki-laki dan bagi-Nya (anak) perempuan?', '', 'https://everyayah.com/data/Alafasy_128kbps/053021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:22', 53, 22, 27, 526, 4806, 'تِلْكَ اِذًا قِسْمَةٌ ضِيْزٰى ', ' Itu tentulah suatu pembagian yang tidak adil.', '', 'https://everyayah.com/data/Alafasy_128kbps/053022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:23', 53, 23, 27, 526, 4807, 'اِنْ هِيَ اِلَّآ اَسْمَاۤءٌ سَمَّيْتُمُوْهَآ اَنْتُمْ وَاٰبَاۤؤُكُمْ مَّآ اَنْزَلَ اللّٰهُ بِهَا مِنْ سُلْطٰنٍۗ اِنْ يَّتَّبِعُوْنَ اِلَّا الظَّنَّ وَمَا تَهْوَى الْاَنْفُسُۚ وَلَقَدْ جَاۤءَهُمْ مِّنْ رَّبِّهِمُ الْهُدٰىۗ', ' (Berhala-berhala) itu tidak lain hanyalah nama-nama yang kamu dan nenek moyangmu ada-adakan. Allah tidak menurunkan suatu keterangan apa pun untuk (menyembah)-nya. Mereka hanya mengikuti dugaan dan apa yang diinginkan oleh hawa nafsu. Padahal, sungguh, mereka benar-benar telah didatangi petunjuk dari Tuhan mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/053023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:24', 53, 24, 27, 526, 4808, 'اَمْ لِلْاِنْسَانِ مَا تَمَنّٰىۖ  ', ' Apakah manusia akan mendapat segala yang diinginkannya?', '', 'https://everyayah.com/data/Alafasy_128kbps/053024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:25', 53, 25, 27, 526, 4809, 'فَلِلّٰهِ الْاٰخِرَةُ وَالْاُوْلٰى ࣖ ', '(Tidak!) Milik Allahlah kehidupan akhirat dan dunia.', '', 'https://everyayah.com/data/Alafasy_128kbps/053025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:26', 53, 26, 27, 526, 4810, '۞ وَكَمْ مِّنْ مَّلَكٍ فِى السَّمٰوٰتِ لَا تُغْنِيْ شَفَاعَتُهُمْ شَيْـًٔا اِلَّا مِنْۢ بَعْدِ اَنْ يَّأْذَنَ اللّٰهُ لِمَنْ يَّشَاۤءُ وَيَرْضٰى ', 'Betapa banyak malaikat di langit yang syafaat (pertolongan) mereka sedikit pun tidak berguna, kecuali apabila Allah telah mengizinkan(-nya untuk diberikan) kepada siapa yang Dia kehendaki dan ridai.', '', 'https://everyayah.com/data/Alafasy_128kbps/053026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:27', 53, 27, 27, 527, 4811, 'اِنَّ الَّذِيْنَ لَا يُؤْمِنُوْنَ بِالْاٰخِرَةِ لَيُسَمُّوْنَ الْمَلٰۤىِٕكَةَ تَسْمِيَةَ الْاُنْثٰى ', ' Sesungguhnya orang-orang yang tidak beriman kepada kehidupan akhirat benar-benar menamai para malaikat dengan nama perempuan.', '', 'https://everyayah.com/data/Alafasy_128kbps/053027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:28', 53, 28, 27, 527, 4812, 'وَمَا لَهُمْ بِهٖ مِنْ عِلْمٍۗ اِنْ يَّتَّبِعُوْنَ اِلَّا الظَّنَّ وَاِنَّ الظَّنَّ لَا يُغْنِيْ مِنَ الْحَقِّ شَيْـًٔاۚ ', 'Padahal, mereka tidak mempunyai pengetahuan tentang hal itu. Mereka tidak lain hanyalah mengikuti dugaan dan sesungguhnya dugaan itu tidak berfaedah sedikit pun terhadap kebenaran.', '', 'https://everyayah.com/data/Alafasy_128kbps/053028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:29', 53, 29, 27, 527, 4813, 'فَاَعْرِضْ عَنْ مَّنْ تَوَلّٰىۙ عَنْ ذِكْرِنَا وَلَمْ يُرِدْ اِلَّا الْحَيٰوةَ الدُّنْيَاۗ  ', ' Tinggalkanlah (Nabi Muhammad) orang yang berpaling dari peringatan Kami (Al-Qur’an) dan hanya menginginkan kehidupan dunia!', '', 'https://everyayah.com/data/Alafasy_128kbps/053029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:30', 53, 30, 27, 527, 4814, 'ذٰلِكَ مَبْلَغُهُمْ مِّنَ الْعِلْمِۗ اِنَّ رَبَّكَ هُوَ اَعْلَمُ بِمَنْ ضَلَّ عَنْ سَبِيْلِهٖۙ وَهُوَ اَعْلَمُ بِمَنِ اهْتَدٰى', ' Itulah kadar pengetahuan mereka. Sesungguhnya Tuhanmulah yang lebih mengetahui siapa yang tersesat dari jalan-Nya dan Dia pulalah yang mengetahui siapa yang mendapat petunjuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/053030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:31', 53, 31, 27, 527, 4815, 'وَلِلّٰهِ مَا فِى السَّمٰوٰتِ وَمَا فِى الْاَرْضِۗ لِيَجْزِيَ الَّذِيْنَ اَسَاۤءُوْا بِمَا عَمِلُوْا وَيَجْزِيَ الَّذِيْنَ اَحْسَنُوْا بِالْحُسْنٰىۚ ', ' Milik Allahlah apa yang ada di langit dan apa yang ada di bumi. (Dengan demikian,) Dia akan memberi balasan kepada orang-orang yang berbuat jahat sesuai dengan apa yang telah mereka kerjakan dan Dia akan memberi balasan kepada orang-orang yang berbuat baik dengan pahala yang lebih baik (surga).', '', 'https://everyayah.com/data/Alafasy_128kbps/053031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:32', 53, 32, 27, 527, 4816, 'اَلَّذِيْنَ يَجْتَنِبُوْنَ كَبٰۤىِٕرَ الْاِثْمِ وَالْفَوَاحِشَ اِلَّا اللَّمَمَۙ اِنَّ رَبَّكَ وَاسِعُ الْمَغْفِرَةِۗ هُوَ اَعْلَمُ بِكُمْ اِذْ اَنْشَاَكُمْ مِّنَ الْاَرْضِ وَاِذْ اَنْتُمْ اَجِنَّةٌ فِيْ بُطُوْنِ اُمَّهٰتِكُمْۗ فَلَا تُزَكُّوْٓا اَنْفُسَكُمْۗ  هُوَ اَعْلَمُ بِمَنِ اتَّقٰى ࣖ ', '(Mereka adalah) orang-orang yang menjauhi dosa-dosa besar dan perbuatan keji. Akan tetapi, mereka (memang) melakukan dosa-dosa kecil. Sesungguhnya Tuhanmu Maha Luas ampunan-Nya. Dia lebih mengetahui dirimu sejak Dia menjadikanmu dari tanah dan ketika kamu masih berupa janin dalam perut ibumu. Maka, janganlah kamu menganggap dirimu suci. Dia lebih mengetahui siapa yang bertakwa.', '', 'https://everyayah.com/data/Alafasy_128kbps/053032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:33', 53, 33, 27, 527, 4817, 'اَفَرَءَيْتَ الَّذِيْ تَوَلّٰىۙ  ', ' Tidakkah engkau melihat orang yang berpaling (dari Al-Qur’an)?', '', 'https://everyayah.com/data/Alafasy_128kbps/053033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:34', 53, 34, 27, 527, 4818, 'وَاَعْطٰى قَلِيْلًا وَّاَكْدٰى ', ' Dia memberikan sedikit (dari apa yang telah disepakati), lalu menahan sisanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/053034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:35', 53, 35, 27, 527, 4819, 'اَعِنْدَهٗ عِلْمُ الْغَيْبِ فَهُوَ يَرٰى ', ' Apakah dia mempunyai pengetahuan tentang yang gaib, sehingga dia dapat melihat(-nya)?', '', 'https://everyayah.com/data/Alafasy_128kbps/053035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:36', 53, 36, 27, 527, 4820, 'اَمْ لَمْ يُنَبَّأْ بِمَا فِيْ صُحُفِ مُوْسٰى  ', ' Apakah belum diberitakan kepadanya apa yang ada dalam lembaran-lembaran (kitab suci yang diturunkan kepada) Musa', '', 'https://everyayah.com/data/Alafasy_128kbps/053036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:37', 53, 37, 27, 527, 4821, 'وَاِبْرٰهِيْمَ الَّذِيْ وَفّٰىٓ ۙ ', ' dan (lembaran-lembaran) Ibrahim yang telah memenuhi janji setianya?', '', 'https://everyayah.com/data/Alafasy_128kbps/053037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:38', 53, 38, 27, 527, 4822, 'اَلَّا تَزِرُ وَازِرَةٌ وِّزْرَ اُخْرٰىۙ  ', ' (Dalam lembaran-lembaran itu terdapat ketetapan) bahwa seseorang yang berdosa tidak akan memikul dosa orang lain,', '', 'https://everyayah.com/data/Alafasy_128kbps/053038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:39', 53, 39, 27, 527, 4823, 'وَاَنْ لَّيْسَ لِلْاِنْسَانِ اِلَّا مَا سَعٰىۙ  ', ' bahwa manusia hanya memperoleh apa yang telah diusahakannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/053039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:40', 53, 40, 27, 527, 4824, 'وَاَنَّ سَعْيَهٗ سَوْفَ يُرٰىۖ', ' bahwa sesungguhnya usahanya itu kelak akan diperlihatkan (kepadanya),', '', 'https://everyayah.com/data/Alafasy_128kbps/053040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:41', 53, 41, 27, 527, 4825, 'ثُمَّ يُجْزٰىهُ الْجَزَاۤءَ الْاَوْفٰىۙ ', 'kemudian dia akan diberi balasan atas (amalnya) itu dengan balasan yang paling sempurna,', '', 'https://everyayah.com/data/Alafasy_128kbps/053041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:42', 53, 42, 27, 527, 4826, 'وَاَنَّ اِلٰى رَبِّكَ الْمُنْتَهٰىۙ  ', ' bahwa sesungguhnya kepada Tuhanmulah kesudahan (segala sesuatu),', '', 'https://everyayah.com/data/Alafasy_128kbps/053042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:43', 53, 43, 27, 527, 4827, 'وَاَنَّهٗ هُوَ اَضْحَكَ وَاَبْكٰى', 'bahwa sesungguhnya Dialah yang menjadikan orang tertawa dan menangis,', '', 'https://everyayah.com/data/Alafasy_128kbps/053043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:44', 53, 44, 27, 527, 4828, 'وَاَنَّهٗ هُوَ اَمَاتَ وَاَحْيَاۙ  ', ' bahwa sesungguhnya Dialah yang mematikan dan menghidupkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/053044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:45', 53, 45, 27, 528, 4829, 'وَاَنَّهٗ خَلَقَ الزَّوْجَيْنِ الذَّكَرَ وَالْاُنْثٰىۙ ', ' bahwa sesungguhnya Dialah yang menciptakan pasangan laki-laki dan perempuan', '', 'https://everyayah.com/data/Alafasy_128kbps/053045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:46', 53, 46, 27, 528, 4830, 'مِنْ نُّطْفَةٍ اِذَا تُمْنٰىۙ  ', ' dari mani ketika dipancarkan', '', 'https://everyayah.com/data/Alafasy_128kbps/053046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:47', 53, 47, 27, 528, 4831, 'وَاَنَّ عَلَيْهِ النَّشْاَةَ الْاُخْرٰىۙ ', ' bahwa sesungguhnya Dialah yang menetapkan penciptaan yang lain (kebangkitan setelah mati),', '', 'https://everyayah.com/data/Alafasy_128kbps/053047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:48', 53, 48, 27, 528, 4832, 'وَاَنَّهٗ هُوَ اَغْنٰى وَاَقْنٰىۙ ', ' bahwa sesungguhnya Dialah yang menganugerahkan kekayaan dan kecukupan,', '', 'https://everyayah.com/data/Alafasy_128kbps/053048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:49', 53, 49, 27, 528, 4833, 'وَاَنَّهٗ هُوَ رَبُّ الشِّعْرٰىۙ', 'bahwa sesungguhnya Dialah Tuhan (yang memiliki) bintang Syi‘ra,704)', '704)Syi‘ra adalah nama bintang yang disembah oleh sebagian orang Arab pada masa Jahiliah.', 'https://everyayah.com/data/Alafasy_128kbps/053049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:50', 53, 50, 27, 528, 4834, 'وَاَنَّهٗٓ اَهْلَكَ عَادًا ۨالْاُوْلٰىۙ', ' dan bahwa sesungguhnya Dialah yang telah membinasakan (kaum) ‘Ad yang terdahulu', '', 'https://everyayah.com/data/Alafasy_128kbps/053050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:51', 53, 51, 27, 528, 4835, 'وَثَمُوْدَا۟ فَمَآ اَبْقٰىۙ', 'dan (kaum) Samud. Tidak seorang pun ditinggalkan-Nya (hidup).', '', 'https://everyayah.com/data/Alafasy_128kbps/053051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:52', 53, 52, 27, 528, 4836, 'وَقَوْمَ نُوْحٍ مِّنْ قَبْلُۗ اِنَّهُمْ كَانُوْا هُمْ اَظْلَمَ وَاَطْغٰىۗ  ', 'Sebelum itu kaum Nuh juga (dibinasakan). Sesungguhnya mereka adalah orang-orang yang lebih zalim dan lebih durhaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/053052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:53', 53, 53, 27, 528, 4837, 'وَالْمُؤْتَفِكَةَ اَهْوٰىۙ  ', ' Dia juga menjungkirbalikkan negeri kaum Lut,', '', 'https://everyayah.com/data/Alafasy_128kbps/053053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:54', 53, 54, 27, 528, 4838, 'فَغَشّٰىهَا مَا غَشّٰىۚ  ', ' lalu Dia menimbuninyadengan apa yang menimpanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/053054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:55', 53, 55, 27, 528, 4839, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكَ تَتَمَارٰى', 'Maka, nikmat Tuhanmu yang manakah yang masih kamu ragukan?', '', 'https://everyayah.com/data/Alafasy_128kbps/053055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:56', 53, 56, 27, 528, 4840, 'هٰذَا نَذِيْرٌ مِّنَ النُّذُرِ الْاُوْلٰى', ' Ini (Nabi Muhammad) adalah salah seorang pemberi peringatan di antara para pemberi peringatan yang terdahulu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/053056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:57', 53, 57, 27, 528, 4841, 'اَزِفَتِ الْاٰزِفَةُ ۚ ', ' (Hari Kiamat) yang dekat makin mendekat. ', '', 'https://everyayah.com/data/Alafasy_128kbps/053057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:58', 53, 58, 27, 528, 4842, 'لَيْسَ لَهَا مِنْ دُوْنِ اللّٰهِ كَاشِفَةٌ  ۗ ', 'Tidak ada yang akan dapat mengungkapkan (terjadinya hari itu) selain Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/053058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:59', 53, 59, 27, 528, 4843, 'اَفَمِنْ هٰذَا الْحَدِيْثِ تَعْجَبُوْنَۙ  ', ' Maka, apakah kamu merasa heran terhadap pemberitaan ini?', '', 'https://everyayah.com/data/Alafasy_128kbps/053059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:60', 53, 60, 27, 528, 4844, 'وَتَضْحَكُوْنَ وَلَا تَبْكُوْنَۙ  ', 'Kamu mentertawakan dan tidak menangisi(-nya),', '', 'https://everyayah.com/data/Alafasy_128kbps/053060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:61', 53, 61, 27, 528, 4845, 'وَاَنْتُمْ سٰمِدُوْنَ ', ' sedangkan kamu lengah (darinya).', '', 'https://everyayah.com/data/Alafasy_128kbps/053061.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:62', 53, 62, 27, 528, 4846, 'فَاسْجُدُوْا لِلّٰهِ وَاعْبُدُوْا ࣖ ۩ ', ' Bersujudlah kepada Allah dan sembahlah (Dia).', '', 'https://everyayah.com/data/Alafasy_128kbps/053062.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:1', 54, 1, 27, 528, 4847, 'اِقْتَرَبَتِ السَّاعَةُ وَانْشَقَّ الْقَمَرُ ', ' Hari Kiamat makin dekat dan bulan terbelah. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:2', 54, 2, 27, 528, 4848, 'وَاِنْ يَّرَوْا اٰيَةً يُّعْرِضُوْا وَيَقُوْلُوْا سِحْرٌ مُّسْتَمِرٌّ', ' Jika mereka (kaum musyrik Makkah) melihat suatu tanda (mukjizat), mereka berpaling dan berkata, “(Ini adalah) sihir yang terus-menerus.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/054002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:3', 54, 3, 27, 528, 4849, 'وَكَذَّبُوْا وَاتَّبَعُوْٓا اَهْوَاۤءَهُمْ وَكُلُّ اَمْرٍ مُّسْتَقِرٌّ', ' Mereka mendustakan (Nabi Muhammad) dan mengikuti keinginan mereka, padahal setiap urusan telah ada ketetapannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/054003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:4', 54, 4, 27, 528, 4850, 'وَلَقَدْ جَاۤءَهُمْ مِّنَ الْاَنْۢبَاۤءِ مَا فِيْهِ مُزْدَجَرٌۙ  ', 'Sungguh, benar-benar telah datang kepada mereka beberapa berita yang di dalamnya terdapat ancaman (terhadap orang-orang kafir).', '', 'https://everyayah.com/data/Alafasy_128kbps/054004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:5', 54, 5, 27, 528, 4851, 'حِكْمَةٌ ۢ بَالِغَةٌ فَمَا تُغْنِ النُّذُرُۙ  ', '(Berita-berita itu adalah) hikmah yang sempurna,705) tetapi peringatan-peringatan itu tidak berguna (bagi mereka).', '705)Hikmah yang sempurna dalam ayat ini adalah ilmu pengetahuan yang agung dan sempurna.', 'https://everyayah.com/data/Alafasy_128kbps/054005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:6', 54, 6, 27, 528, 4852, 'فَتَوَلَّ عَنْهُمْ ۘ يَوْمَ يَدْعُ الدَّاعِ اِلٰى شَيْءٍ نُّكُرٍۙ  ', 'Maka, berpalinglah (Nabi Muhammad) dari mereka. Pada hari (ketika) penyeru (malaikat) mengajak (mereka) pada sesuatu yang tidak menyenangkan (hari Pembalasan),', '', 'https://everyayah.com/data/Alafasy_128kbps/054006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:7', 54, 7, 27, 529, 4853, 'خُشَّعًا اَبْصَارُهُمْ يَخْرُجُوْنَ مِنَ الْاَجْدَاثِ كَاَنَّهُمْ جَرَادٌ مُّنْتَشِرٌۙ  ', ' pandangan mereka tertunduk. Mereka keluar (berhamburan) dari kubur seperti belalang yang beterbangan.', '', 'https://everyayah.com/data/Alafasy_128kbps/054007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:8', 54, 8, 27, 529, 4854, 'مُّهْطِعِيْنَ اِلَى الدَّاعِۗ يَقُوْلُ الْكٰفِرُوْنَ هٰذَا يَوْمٌ عَسِرٌ ', ' Mereka bersegera datang kepada penyeru itu. Orang-orang kafir berkata, “Ini adalah hari yang sulit.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/054008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:9', 54, 9, 27, 529, 4855, '۞ كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوْحٍ فَكَذَّبُوْا عَبْدَنَا وَقَالُوْا مَجْنُوْنٌ وَّازْدُجِرَ', 'Sebelum mereka, kaum Nuh juga telah mendustakan (rasul). Mereka mendustakan hamba Kami (Nuh) dan mengatakan, “(Dia) orang gila!” Dia pun dibentak (dengan cacian dan lainnya). ', '', 'https://everyayah.com/data/Alafasy_128kbps/054009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:10', 54, 10, 27, 529, 4856, 'فَدَعَا رَبَّهٗٓ اَنِّيْ مَغْلُوْبٌ فَانْتَصِرْ', 'Dia (Nuh) lalu mengadu kepada Tuhannya, “Sesungguhnya aku telah dikalahkan, maka tolonglah (aku).”', '', 'https://everyayah.com/data/Alafasy_128kbps/054010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:11', 54, 11, 27, 529, 4857, 'فَفَتَحْنَآ اَبْوَابَ السَّمَاۤءِ بِمَاۤءٍ مُّنْهَمِرٍۖ  ', 'Lalu, Kami membukakan pintu-pintu langit dengan (menurunkan) air yang tercurah.', '', 'https://everyayah.com/data/Alafasy_128kbps/054011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:12', 54, 12, 27, 529, 4858, 'وَّفَجَّرْنَا الْاَرْضَ عُيُوْنًا فَالْتَقَى الْمَاۤءُ عَلٰٓى اَمْرٍ قَدْ قُدِرَ ۚ', 'Kami pun menjadikan bumi menyemburkan banyak mata air. Maka, berkumpullah semua air itu sehingga (meluap dan menimbulkan) bencana yang telah ditetapkan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:13', 54, 13, 27, 529, 4859, 'وَحَمَلْنٰهُ عَلٰى ذَاتِ اَلْوَاحٍ وَّدُسُرٍۙ  ', 'Kami mengangkut dia (Nuh) ke atas (kapal) yang terbuat dari papan dan pasak', '', 'https://everyayah.com/data/Alafasy_128kbps/054013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:14', 54, 14, 27, 529, 4860, 'تَجْرِيْ بِاَعْيُنِنَاۚ جَزَاۤءً لِّمَنْ كَانَ كُفِرَ ', 'yang berlayar dengan pengawasan Kami sebagai balasan (kebaikan) bagi orang yang telah diingkari (kaumnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/054014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:15', 54, 15, 27, 529, 4861, 'وَلَقَدْ تَّرَكْنٰهَآ اٰيَةً فَهَلْ مِنْ مُّدَّكِرٍ', 'Sungguh, Kami benar-benar telah menjadikan (kapal) itu sebagai tanda (pelajaran). Maka, adakah orang yang mau mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/054015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:16', 54, 16, 27, 529, 4862, 'فَكَيْفَ كَانَ عَذَابِيْ وَنُذُرِ ', ' Betapa dahsyatnya azab dan peringatan-Ku! ', '', 'https://everyayah.com/data/Alafasy_128kbps/054016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:17', 54, 17, 27, 529, 4863, 'وَلَقَدْ يَسَّرْنَا الْقُرْاٰنَ لِلذِّكْرِ فَهَلْ مِنْ مُّدَّكِرٍ ', ' Sungguh, Kami benar-benar telah memudahkan Al-Qur’an sebagai pelajaran. Maka, adakah orang yang mau mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/054017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:18', 54, 18, 27, 529, 4864, 'كَذَّبَتْ عَادٌ فَكَيْفَ كَانَ عَذَابِيْ وَنُذُرِ ', ' (Kaum) ‘Ad pun telah mendustakan (rasul mereka). Maka, betapa dahsyatnya azab dan peringatan-Ku! ', '', 'https://everyayah.com/data/Alafasy_128kbps/054018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:19', 54, 19, 27, 529, 4865, 'اِنَّآ اَرْسَلْنَا عَلَيْهِمْ رِيْحًا صَرْصَرًا فِيْ يَوْمِ نَحْسٍ مُّسْتَمِرٍّۙ  ', 'Sesungguhnya Kami telah mengembuskan angin yang sangat kencang kepada mereka pada hari nahas yang terus-menerus, ', '', 'https://everyayah.com/data/Alafasy_128kbps/054019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:20', 54, 20, 27, 529, 4866, 'تَنْزِعُ النَّاسَۙ كَاَنَّهُمْ اَعْجَازُ نَخْلٍ مُّنْقَعِرٍ ', ' yang membuat manusia bergelimpangan, seakan-akan mereka itu pohon-pohon kurma yang tumbang dengan akar-akarnya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:21', 54, 21, 27, 529, 4867, 'فَكَيْفَ كَانَ عَذَابِيْ وَنُذُرِ', 'Maka, betapa dahsyatnya azab dan peringatan-Ku!', '', 'https://everyayah.com/data/Alafasy_128kbps/054021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:22', 54, 22, 27, 529, 4868, 'وَلَقَدْ يَسَّرْنَا الْقُرْاٰنَ لِلذِّكْرِ فَهَلْ مِنْ مُّدَّكِرٍ ࣖ ', ' Sungguh, Kami benar-benar telah memudahkan Al-Qur’an sebagai pelajaran. Maka, adakah orang yang mau mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/054022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:23', 54, 23, 27, 529, 4869, 'كَذَّبَتْ ثَمُوْدُ بِالنُّذُرِ', '(Kaum) Samud pun telah mendustakan peringatan-peringatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/054023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:24', 54, 24, 27, 529, 4870, 'فَقَالُوْٓا اَبَشَرًا مِّنَّا وَاحِدًا نَّتَّبِعُهٗٓ  ۙاِنَّآ اِذًا لَّفِيْ ضَلٰلٍ وَّسُعُرٍ', ' Mereka berkata, “Bagaimana kita akan mengikuti seorang manusia (biasa) di antara kita? Sesungguhnya kalau begitu kita benar-benar telah sesat dan gila. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:25', 54, 25, 27, 529, 4871, 'ءَاُلْقِيَ الذِّكْرُ عَلَيْهِ مِنْۢ بَيْنِنَا بَلْ هُوَ كَذَّابٌ اَشِرٌ ', ' Apakah wahyu itu diturunkan kepadanya di antara kita? Pastilah dia (Saleh) seorang yang sangat pendusta lagi sombong.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/054025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:26', 54, 26, 27, 529, 4872, 'سَيَعْلَمُوْنَ غَدًا مَّنِ الْكَذَّابُ الْاَشِرُ ', ' Kelak mereka akan mengetahui siapa yang sebenarnya sangat pendusta lagi sombong itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/054026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:27', 54, 27, 27, 529, 4873, 'اِنَّا مُرْسِلُوا النَّاقَةِ فِتْنَةً لَّهُمْ فَارْتَقِبْهُمْ وَاصْطَبِرْۖ  ', ' Sesungguhnya Kami akan mengirimkan unta betina sebagai ujian bagi mereka, maka tunggulah mereka dan bersabarlah (wahai Saleh).', '', 'https://everyayah.com/data/Alafasy_128kbps/054027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:28', 54, 28, 27, 530, 4874, 'وَنَبِّئْهُمْ اَنَّ الْمَاۤءَ قِسْمَةٌ ۢ بَيْنَهُمْۚ  كُلُّ شِرْبٍ مُّحْتَضَرٌ ', ' Beri tahulah mereka bahwa air itu dibagi di antara mereka (dengan unta betina itu). Setiap pihak berhak mendapat giliran minum.', '', 'https://everyayah.com/data/Alafasy_128kbps/054028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:29', 54, 29, 27, 530, 4875, 'فَنَادَوْا صَاحِبَهُمْ فَتَعَاطٰى فَعَقَرَ ', 'Mereka memanggil kawannya, lalu dia menangkap (unta itu) dan menyembelihnya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:30', 54, 30, 27, 530, 4876, 'فَكَيْفَ كَانَ عَذَابِيْ وَنُذُرِ ', ' Betapa dahsyatnya azab dan peringatan-Ku!', '', 'https://everyayah.com/data/Alafasy_128kbps/054030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:31', 54, 31, 27, 530, 4877, 'اِنَّآ اَرْسَلْنَا عَلَيْهِمْ صَيْحَةً وَّاحِدَةً فَكَانُوْا كَهَشِيْمِ الْمُحْتَظِرِ', ' Kami mengirimkan atas mereka suara menggelegar satu kali. Maka, jadilah mereka seperti batang-batang kering yang lapuk milik pembuat kandang ternak. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:32', 54, 32, 27, 530, 4878, 'وَلَقَدْ يَسَّرْنَا الْقُرْاٰنَ لِلذِّكْرِ فَهَلْ مِنْ مُّدَّكِرٍ ', ' Sungguh, Kami benar-benar telah memudahkan Al-Qur’an sebagai pelajaran. Adakah orang yang mau mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/054032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:33', 54, 33, 27, 530, 4879, 'كَذَّبَتْ قَوْمُ لُوْطٍ ۢبِالنُّذُرِ ', ' Kaum Lut pun telah mendustakan peringatan-peringatan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:34', 54, 34, 27, 530, 4880, 'اِنَّآ اَرْسَلْنَا عَلَيْهِمْ حَاصِبًا اِلَّآ اٰلَ لُوْطٍ ۗنَجَّيْنٰهُمْ بِسَحَرٍۙ', ' Sesungguhnya Kami menimpakan atas mereka badai batu, kecuali pengikut Lut. Kami menyelamatkan mereka sebelum fajar menyingsing', '', 'https://everyayah.com/data/Alafasy_128kbps/054034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:35', 54, 35, 27, 530, 4881, 'نِّعْمَةً مِّنْ عِنْدِنَاۗ  كَذٰلِكَ نَجْزِيْ مَنْ شَكَرَ ', ' sebagai nikmat dari Kami. Demikianlah Kami memberi balasan kepada orang-orang yang bersyukur. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:36', 54, 36, 27, 530, 4882, 'وَلَقَدْ اَنْذَرَهُمْ بَطْشَتَنَا فَتَمَارَوْا بِالنُّذُرِ ', ' Sungguh, dia (Lut) benar-benar telah memperingatkan mereka akan hukuman Kami, tetapi mereka membantah peringatan itu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:37', 54, 37, 27, 530, 4883, 'وَلَقَدْ رَاوَدُوْهُ عَنْ ضَيْفِهٖ فَطَمَسْنَآ اَعْيُنَهُمْ فَذُوْقُوْا عَذَابِيْ وَنُذُرِ ', ' Sungguh, mereka benar-benar telah membujuknya berkali-kali (agar menyerahkan) tamunya (kepada mereka). Lalu, Kami butakan mata mereka. Maka, rasakanlah azab-Ku dan peringatan-peringatan-Ku!', '', 'https://everyayah.com/data/Alafasy_128kbps/054037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:38', 54, 38, 27, 530, 4884, 'وَلَقَدْ صَبَّحَهُمْ بُكْرَةً عَذَابٌ مُّسْتَقِرٌّۚ  ', ' Sungguh, pada esok harinya mereka benar-benar ditimpa azab yang terus-menerus.', '', 'https://everyayah.com/data/Alafasy_128kbps/054038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:39', 54, 39, 27, 530, 4885, 'فَذُوْقُوْا عَذَابِيْ وَنُذُرِ ', ' Maka, rasakanlah azab-Ku dan peringatan-peringatan-Ku!', '', 'https://everyayah.com/data/Alafasy_128kbps/054039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:40', 54, 40, 27, 530, 4886, 'وَلَقَدْ يَسَّرْنَا الْقُرْاٰنَ لِلذِّكْرِ فَهَلْ مِنْ مُّدَّكِرٍ ࣖ', 'Sungguh, Kami benar-benar telah memudahkan Al-Qur’an sebagai pelajaran. Maka, adakah orang yang mau mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/054040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:41', 54, 41, 27, 530, 4887, 'وَلَقَدْ جَاۤءَ اٰلَ فِرْعَوْنَ النُّذُرُۚ  ', ' Sungguh, berbagai peringatan benar-benar telah datang kepada pengikut Fir‘aun.', '', 'https://everyayah.com/data/Alafasy_128kbps/054041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:42', 54, 42, 27, 530, 4888, 'كَذَّبُوْا بِاٰيٰتِنَا كُلِّهَا فَاَخَذْنٰهُمْ اَخْذَ عَزِيْزٍ مُّقْتَدِرٍ ', ' Mereka mendustakan semua tanda-tanda (kebesaran) Kami. Maka, Kami mengazab mereka dengan azab (Tuhan) Yang Maha Perkasa lagi Maha Kuasa.', '', 'https://everyayah.com/data/Alafasy_128kbps/054042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:43', 54, 43, 27, 530, 4889, 'اَكُفَّارُكُمْ خَيْرٌ مِّنْ اُولٰۤىِٕكُمْ اَمْ لَكُمْ بَرَاۤءَةٌ فِى الزُّبُرِۚ', 'Apakah orang-orang kafir di lingkunganmu (kaum Quraisy) lebih baik daripada mereka (kaum terdahulu) ataukah kamu telah mempunyai (jaminan) kebebasan (dari azab) dalam kitab-kitab terdahulu? ', '', 'https://everyayah.com/data/Alafasy_128kbps/054043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:44', 54, 44, 27, 530, 4890, 'اَمْ يَقُوْلُوْنَ نَحْنُ جَمِيْعٌ مُّنْتَصِرٌ ', ' Bahkan, apakah mereka mengatakan, “Kami adalah golongan yang pasti menang.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/054044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:45', 54, 45, 27, 530, 4891, 'سَيُهْزَمُ الْجَمْعُ وَيُوَلُّوْنَ الدُّبُرَ', 'Golongan itu pasti akan dikalahkan dan mereka berbalik ke belakang (mundur). ', '', 'https://everyayah.com/data/Alafasy_128kbps/054045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:46', 54, 46, 27, 530, 4892, 'بَلِ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ اَدْهٰى وَاَمَرُّ ', ' Bahkan hari Kiamat itulah hari yang dijanjikan kepada mereka. Hari Kiamat itu lebih dahsyat dan lebih pahit. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:47', 54, 47, 27, 530, 4893, 'اِنَّ الْمُجْرِمِيْنَ فِيْ ضَلٰلٍ وَّسُعُرٍۘ ', 'Sesungguhnya para pendurhaka berada dalam kesesatan dan akan berada dalam (neraka) Sa‘ir (yang menyala-nyala). ', '', 'https://everyayah.com/data/Alafasy_128kbps/054047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:48', 54, 48, 27, 530, 4894, 'يَوْمَ يُسْحَبُوْنَ فِى النَّارِ عَلٰى وُجُوْهِهِمْۗ ذُوْقُوْا مَسَّ سَقَرَ', ' Pada hari (ketika) mereka diseret ke neraka dengan wajah (tertelungkup), (dikatakan kepada mereka,) “Rasakanlah sentuhan (api neraka) Saqar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/054048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:49', 54, 49, 27, 530, 4895, 'اِنَّا كُلَّ شَيْءٍ خَلَقْنٰهُ بِقَدَرٍ ', ' Sesungguhnya Kami menciptakan segala sesuatu sesuai dengan ukuran.', '', 'https://everyayah.com/data/Alafasy_128kbps/054049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:50', 54, 50, 27, 531, 4896, 'وَمَآ اَمْرُنَآ اِلَّا وَاحِدَةٌ كَلَمْحٍ ۢبِالْبَصَرِ ', 'Perintah Kami (ketika menghendaki sesuatu) hanyalah (dengan perkataan) sekali saja seperti kejapan mata. ', '', 'https://everyayah.com/data/Alafasy_128kbps/054050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:51', 54, 51, 27, 531, 4897, 'وَلَقَدْ اَهْلَكْنَآ اَشْيَاعَكُمْ فَهَلْ مِنْ مُّدَّكِرٍ ', ' Sungguh, Kami benar-benar telah membinasakan orang yang (kekafirannya) serupa dengan kamu. Maka, adakah orang yang mau mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/054051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:52', 54, 52, 27, 531, 4898, 'وَكُلُّ شَيْءٍ فَعَلُوْهُ فِى الزُّبُرِ ', 'Segala sesuatu yang telah mereka perbuat (tertulis) dalam buku-buku catatan (amal).', '', 'https://everyayah.com/data/Alafasy_128kbps/054052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:53', 54, 53, 27, 531, 4899, 'وَكُلُّ صَغِيْرٍ وَّكَبِيْرٍ مُّسْتَطَرٌ ', ' Segala (amalan) yang kecil atau yang besar (semuanya) tertulis (di Lauhulmahfuz). ', '', 'https://everyayah.com/data/Alafasy_128kbps/054053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:54', 54, 54, 27, 531, 4900, 'اِنَّ الْمُتَّقِيْنَ فِيْ جَنّٰتٍ وَّنَهَرٍۙ  ', ' Sesungguhnya orang-orang yang bertakwa berada di taman-taman dan sungai', '', 'https://everyayah.com/data/Alafasy_128kbps/054054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('54:55', 54, 55, 27, 531, 4901, 'فِيْ مَقْعَدِ صِدْقٍ عِنْدَ مَلِيْكٍ مُّقْتَدِرٍ ࣖ ', ' di tempat yang disenangi di sisi Tuhan Yang Maha Kuasa.', '', 'https://everyayah.com/data/Alafasy_128kbps/054055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:1', 55, 1, 27, 531, 4902, 'اَلرَّحْمٰنُۙ  ', ' (Allah) Yang Maha Pengasih,', '', 'https://everyayah.com/data/Alafasy_128kbps/055001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:2', 55, 2, 27, 531, 4903, 'عَلَّمَ الْقُرْاٰنَۗ ', ' telah mengajarkan Al-Qur’an.', '', 'https://everyayah.com/data/Alafasy_128kbps/055002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:3', 55, 3, 27, 531, 4904, 'خَلَقَ الْاِنْسَانَۙ ', 'Dia menciptakan manusia.', '', 'https://everyayah.com/data/Alafasy_128kbps/055003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:4', 55, 4, 27, 531, 4905, 'عَلَّمَهُ الْبَيَانَ ', 'Dia mengajarinya pandai menjelaskan.', '', 'https://everyayah.com/data/Alafasy_128kbps/055004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:5', 55, 5, 27, 531, 4906, 'اَلشَّمْسُ وَالْقَمَرُ بِحُسْبَانٍۙ ', ' Matahari dan bulan (beredar) sesuai dengan perhitungan.', '', 'https://everyayah.com/data/Alafasy_128kbps/055005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:6', 55, 6, 27, 531, 4907, 'وَّالنَّجْمُ وَالشَّجَرُ يَسْجُدَانِ ', ' Tetumbuhan dan pepohonan tunduk (kepada-Nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/055006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:7', 55, 7, 27, 531, 4908, 'وَالسَّمَاۤءَ رَفَعَهَا وَوَضَعَ الْمِيْزَانَۙ  ', 'Langit telah Dia tinggikan dan Dia telah menciptakan timbangan (keadilan dan keseimbangan)', '', 'https://everyayah.com/data/Alafasy_128kbps/055007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:8', 55, 8, 27, 531, 4909, 'اَلَّا تَطْغَوْا فِى الْمِيْزَانِ ', ' agar kamu tidak melampaui batas dalam timbangan itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/055008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:9', 55, 9, 27, 531, 4910, 'وَاَقِيْمُوا الْوَزْنَ بِالْقِسْطِ وَلَا تُخْسِرُوا الْمِيْزَانَ ', 'Tegakkanlah timbangan itu dengan adil dan janganlah kamu mengurangi timbangan itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/055009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:10', 55, 10, 27, 531, 4911, 'وَالْاَرْضَ وَضَعَهَا لِلْاَنَامِۙ  ', ' Bumi telah Dia bentangkan untuk makhluk(-Nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/055010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:11', 55, 11, 27, 531, 4912, 'فِيْهَا فَاكِهَةٌ وَّالنَّخْلُ ذَاتُ الْاَكْمَامِۖ  ', 'Padanya terdapat buah-buahan dan pohon kurma yang mempunyai kelopak mayang,', '', 'https://everyayah.com/data/Alafasy_128kbps/055011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:12', 55, 12, 27, 531, 4913, 'وَالْحَبُّ ذُو الْعَصْفِ وَالرَّيْحَانُۚ  ', ' biji-bijian yang berkulit, dan bunga-bunga yang harum baunya.', '', 'https://everyayah.com/data/Alafasy_128kbps/055012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:13', 55, 13, 27, 531, 4914, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:14', 55, 14, 27, 531, 4915, 'خَلَقَ الْاِنْسَانَ مِنْ صَلْصَالٍ كَالْفَخَّارِ ', ' Dia telah menciptakan manusia dari tanah kering seperti tembikar.', '', 'https://everyayah.com/data/Alafasy_128kbps/055014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:15', 55, 15, 27, 531, 4916, 'وَخَلَقَ الْجَاۤنَّ مِنْ مَّارِجٍ مِّنْ نَّارٍۚ  ', ' Dia juga telah menciptakan jin dari nyala api tanpa asap.', '', 'https://everyayah.com/data/Alafasy_128kbps/055015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:16', 55, 16, 27, 531, 4917, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:17', 55, 17, 27, 532, 4918, 'رَبُّ الْمَشْرِقَيْنِ وَرَبُّ الْمَغْرِبَيْنِۚ ', ' (Dialah) Tuhan kedua tempat terbit (matahari pada musim panas dan musim dingin) dan Tuhan kedua tempat terbenam (matahari pada kedua musim itu). ', '', 'https://everyayah.com/data/Alafasy_128kbps/055017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:18', 55, 18, 27, 532, 4919, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', '.Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:19', 55, 19, 27, 532, 4920, 'مَرَجَ الْبَحْرَيْنِ يَلْتَقِيٰنِۙ', ' Dia membiarkan dua laut (tawar dan asin) bertemu.', '', 'https://everyayah.com/data/Alafasy_128kbps/055019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:20', 55, 20, 27, 532, 4921, 'بَيْنَهُمَا بَرْزَخٌ لَّا يَبْغِيٰنِۚ', 'Di antara keduanya ada pembatas yang tidak dilampaui oleh masing-masing.', '', 'https://everyayah.com/data/Alafasy_128kbps/055020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:21', 55, 21, 27, 532, 4922, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:22', 55, 22, 27, 532, 4923, 'يَخْرُجُ مِنْهُمَا اللُّؤْلُؤُ وَالْمَرْجَانُۚ', ' Dari keduanya keluar mutiara dan marjan.', '', 'https://everyayah.com/data/Alafasy_128kbps/055022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:23', 55, 23, 27, 532, 4924, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:24', 55, 24, 27, 532, 4925, 'وَلَهُ الْجَوَارِ الْمُنْشَاٰتُ فِى الْبَحْرِ كَالْاَعْلَامِۚ  ', ' Milik-Nyalah (bahtera) buatan manusia yang berlayar di laut laksana gunung-gunung.', '', 'https://everyayah.com/data/Alafasy_128kbps/055024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:25', 55, 25, 27, 532, 4926, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ࣖ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:26', 55, 26, 27, 532, 4927, 'كُلُّ مَنْ عَلَيْهَا فَانٍۖ  ', ' Semua yang ada di atasnya (bumi) itu akan binasa.', '', 'https://everyayah.com/data/Alafasy_128kbps/055026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:27', 55, 27, 27, 532, 4928, 'وَّيَبْقٰى وَجْهُ رَبِّكَ ذُو الْجَلٰلِ وَالْاِكْرَامِۚ  ', ' (Akan tetapi,) wajah (zat) Tuhanmu yang memiliki kebesaran dan kemuliaan tetap kekal.', '', 'https://everyayah.com/data/Alafasy_128kbps/055027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:28', 55, 28, 27, 532, 4929, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:29', 55, 29, 27, 532, 4930, 'يَسْـَٔلُهٗ مَنْ فِى السَّمٰوٰتِ وَالْاَرْضِۗ  كُلَّ يَوْمٍ هُوَ فِيْ شَأْنٍۚ', ' Siapa yang ada di langit dan bumi selalu meminta kepada-Nya. Setiap hari Dia menangani urusan.', '', 'https://everyayah.com/data/Alafasy_128kbps/055029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:30', 55, 30, 27, 532, 4931, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:31', 55, 31, 27, 532, 4932, 'سَنَفْرُغُ لَكُمْ اَيُّهَ الثَّقَلٰنِۚ  ', 'Kami akan mencurahkan perhatian kepadamu, wahai manusia dan jin.', '', 'https://everyayah.com/data/Alafasy_128kbps/055031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:32', 55, 32, 27, 532, 4933, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:33', 55, 33, 27, 532, 4934, 'يٰمَعْشَرَ الْجِنِّ وَالْاِنْسِ اِنِ اسْتَطَعْتُمْ اَنْ تَنْفُذُوْا مِنْ اَقْطَارِ السَّمٰوٰتِ وَالْاَرْضِ فَانْفُذُوْاۗ  لَا تَنْفُذُوْنَ اِلَّا بِسُلْطٰنٍۚ ', ' Wahai segenap jin dan manusia, jika kamu sanggup menembus (melintasi) penjuru langit dan bumi, tembuslah. Kamu tidak akan mampu menembusnya, kecuali dengan kekuatan (dari Allah). ', '', 'https://everyayah.com/data/Alafasy_128kbps/055033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:34', 55, 34, 27, 532, 4935, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:35', 55, 35, 27, 532, 4936, 'يُرْسَلُ عَلَيْكُمَا شُوَاظٌ مِّنْ نَّارٍۙ وَّنُحَاسٌ فَلَا تَنْتَصِرَانِۚ ', 'Kepadamu, (wahai jin dan manusia,) disemburkan nyala api dan (ditumpahkan) cairan tembaga panas sehingga kamu tidak dapat menyelamatkan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/055035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:36', 55, 36, 27, 532, 4937, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:37', 55, 37, 27, 532, 4938, 'فَاِذَا انْشَقَّتِ السَّمَاۤءُ فَكَانَتْ وَرْدَةً كَالدِّهَانِۚ ', ' Maka, apabila langit terbelah, lalu (warnanya) menjadi merah mawar seperti (kilauan) minyak, (terjadilah kengerian yang hebat).', '', 'https://everyayah.com/data/Alafasy_128kbps/055037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:38', 55, 38, 27, 532, 4939, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:39', 55, 39, 27, 532, 4940, 'فَيَوْمَئِذٍ لَّا يُسْـَٔلُ عَنْ ذَنْۢبِهٖٓ اِنْسٌ وَّلَا جَاۤنٌّۚ  ', ' Maka, pada hari itu manusia dan jin tidak ditanya tentang dosanya706)', '706) Mereka tidak ditanya untuk membuktikan amal perbuatannya, tetapi pada saatnya akan ditanya untuk mempertanggungjawabkannya.', 'https://everyayah.com/data/Alafasy_128kbps/055039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:40', 55, 40, 27, 532, 4941, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ  ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:41', 55, 41, 27, 533, 4942, 'يُعْرَفُ الْمُجْرِمُوْنَ بِسِيْمٰهُمْ فَيُؤْخَذُ بِالنَّوَاصِيْ وَالْاَقْدَامِۚ  ', ' Para pendosa dikenali dengan tanda-tandanya, lalu direnggut ubun-ubun dan kakinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/055041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:42', 55, 42, 27, 533, 4943, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:43', 55, 43, 27, 533, 4944, 'هٰذِهٖ جَهَنَّمُ الَّتِيْ يُكَذِّبُ بِهَا الْمُجْرِمُوْنَۘ ', ' Inilah (neraka) Jahanam yang didustakan oleh para pendosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/055043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:44', 55, 44, 27, 533, 4945, 'يَطُوْفُوْنَ بَيْنَهَا وَبَيْنَ حَمِيْمٍ اٰنٍۚ  ', 'Mereka bolak-balik di antaranya (api neraka) dan air mendidih yang sangat panas.', '', 'https://everyayah.com/data/Alafasy_128kbps/055044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:45', 55, 45, 27, 533, 4946, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ࣖ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:46', 55, 46, 27, 533, 4947, 'وَلِمَنْ خَافَ مَقَامَ رَبِّهٖ جَنَّتٰنِۚ', ' Bagi siapa yang takut pada keagungan Tuhannya disediakan dua surga.', '', 'https://everyayah.com/data/Alafasy_128kbps/055046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:47', 55, 47, 27, 533, 4948, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۙ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:48', 55, 48, 27, 533, 4949, 'ذَوَاتَآ اَفْنَانٍۚ ', 'Kedua surga itu mempunyai (pepohonan) yang bercabang-cabang.', '', 'https://everyayah.com/data/Alafasy_128kbps/055048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:49', 55, 49, 27, 533, 4950, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:50', 55, 50, 27, 533, 4951, 'فِيْهِمَا عَيْنٰنِ تَجْرِيٰنِۚ ', ' Di dalam kedua (surga) itu terdapat dua mata air yang memancar.', '', 'https://everyayah.com/data/Alafasy_128kbps/055050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:51', 55, 51, 27, 533, 4952, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:52', 55, 52, 27, 533, 4953, 'فِيْهِمَا مِنْ كُلِّ فَاكِهَةٍ زَوْجٰنِۚ ', ' Di dalam kedua (surga) itu terdapat aneka buah-buahan yang berpasang-pasangan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/055052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:53', 55, 53, 27, 533, 4954, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:54', 55, 54, 27, 533, 4955, 'مُتَّكِـِٕيْنَ عَلٰى فُرُشٍۢ بَطَاۤىِٕنُهَا مِنْ اِسْتَبْرَقٍۗ وَجَنَا الْجَنَّتَيْنِ دَانٍۚ ', ' Mereka berbaring di atas permadani yang bagian dalamnya (terbuat) dari sutera tebal. Buah-buahan di kedua surga itu (dapat) dipetik dari dekat. ', '', 'https://everyayah.com/data/Alafasy_128kbps/055054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:55', 55, 55, 27, 533, 4956, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:56', 55, 56, 27, 533, 4957, 'فِيْهِنَّ قٰصِرٰتُ الطَّرْفِۙ لَمْ يَطْمِثْهُنَّ اِنْسٌ قَبْلَهُمْ وَلَا جَاۤنٌّۚ  ', 'Di dalamnya ada (bidadari) yang membatasi pandangan (hanya untuk pasangannya) yang tidak pernah disentuh oleh manusia sebelum mereka dan tidak (pula) oleh jin.', '', 'https://everyayah.com/data/Alafasy_128kbps/055056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:57', 55, 57, 27, 533, 4958, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ ', 'Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055057.mp3');
