INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:59', 55, 59, 27, 533, 4960, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055059.mp3');
