INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:67', 55, 67, 27, 533, 4968, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ  ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055067.mp3');
