INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:69', 55, 69, 27, 534, 4970, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055069.mp3');
